mapper.select:
SELECT p.id, p.device_id, p.prediction_date, p.target_month, p.predicted_fault_count, p.failure_probability, p.fault_count_lower, p.fault_count_upper, p.feature_importance, p.model_type, p.created_at, e.code AS device_code, e.name AS device_name, h.health_score AS current_health_score, h.risk_level AS current_risk_level FROM ai_fault_prediction p LEFT JOIN equipment e ON p.device_id = e.id LEFT JOIN ( SELECT device_id, health_score, risk_level FROM ai_device_health WHERE (device_id, record_date) IN ( SELECT device_id, MAX(record_date) FROM ai_device_health GROUP BY device_id ) ) h ON p.device_id = h.device_id WHERE p.prediction_date = ( SELECT MAX(prediction_date) FROM ai_fault_prediction WHERE device_id = p.device_id )
AND e.code LIKE CONCAT('%', #{deviceCode}, '%')
AND p.failure_probability >= #{minProbability}
ORDER BY p.failure_probability DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(DISTINCT p.device_id) FROM ai_fault_prediction p LEFT JOIN equipment e ON p.device_id = e.id WHERE p.prediction_date = ( SELECT MAX(prediction_date) FROM ai_fault_prediction WHERE device_id = p.device_id )
AND e.code LIKE CONCAT('%', #{deviceCode}, '%')
AND p.failure_probability >= #{minProbability}

SELECT COUNT(DISTINCT device_id)
FROM ai_fault_prediction
WHERE target_month = #{targetMonth}

SELECT COUNT(DISTINCT device_id)
FROM ai_fault_prediction
WHERE failure_probability > #{probabilityThreshold}
  AND prediction_date = (
      SELECT MAX(prediction_date) FROM ai_fault_prediction WHERE device_id = ai_fault_prediction.device_id
  )
